    type: 'paragraph',
    paragraph: {
      rich_text: [{ type: 'text', text: { content: meetingInfo.agenda || '（请填写议题）' } }]
    }
  },
  {
    object: 'block',
    type: 'heading_2',
    heading_2: {
      rich_text: [{ type: 'text', text: { content: '✅ 行动项' } }]
    }
  },
  {
    object: 'block',
    type: 'to_do',
    to_do: {
      checked: false,
      rich_text: [{ type: 'text', text: { content: '行动项1' } }]
    }
  },
  {
    object: 'block',
    type: 'to_do',
    to_do: {
      checked: false,
      rich_text: [{ type: 'text', text: { content: '行动项2' } }]
    }
  },
  {
    object: 'block',
    type: 'divider',
    divider: {}
  },
  {
    object: 'block',
    type: 'heading_2',
    heading_2: {
      rich_text: [{ type: 'text', text: { content: '📌 下次会议安排' } }]
    }
  },
  {
    object: 'block',
    type: 'paragraph',
    paragraph: {
      rich_text: [{ type: 'text', text: { content: '（待定）' } }]
    }
  }
];

// 使用模板创建会议记录
async function createMeetingRecord() {
  const meetingInfo = {
    title: 'Q4产品规划会议',
    date: '2024-01-15 14:00-16:00',
    attendees: ['张三', '李四', '王五'],
    agenda: '讨论下一季度产品方向和资源分配'
  };

  const response = await notion.pages.create({
    parent: { page_id: 'workspace-page-id' },
    properties: {
      title: {
        title: [{ type: 'text', text: { content: `会议记录 - ${meetingInfo.date}` } }]
      }
    },
    children: meetingTemplate(meetingInfo)
  });

  return response;
}

createMeetingRecord().then(page => {
  console.log('会议记录页面已创建:', page.id);
  console.log('页面链接:', `https://notion.so/${page.id.replace(/-/g, '')}`);
});
```



## 常见错误

- 过度嵌套：创建超过5层以上的页面层级，导致导航困难且难以维护
- 滥用数据库：将简单笔记用数据库管理，增加使用复杂度
- 忽视快捷键：始终使用鼠标操作，降低编辑效率
- 模板过于复杂：设计的模板包含过多预设内容，反而限制灵活性
- 块类型混乱：在需要有序内容时使用无序列表，降低可读性
- 忽略页面属性：创建页面时不设置封面、图标等视觉标识，导致难以识别
- 复制代替模板：每次手动复制内容而非创建可复用模板
- 版本管理缺失：不使用Page History功能，重要修改前未创建备份
- 链接孤岛：创建页面间无关联的内容，失去知识网络价值
- 过度依赖拖拽：频繁使用拖拽调整内容，不利用快捷键和命令菜单


## 最佳实践

- 保持扁平化结构：尽量将页面层级控制在3层以内，使用Database管理复杂关系
- 建立页面命名规范：使用统一的命名格式，如「类型-名称-日期」或emoji+标题
- 善用Favorites：将高频访问页面加入收藏夹，提升导航效率
- 设计标准化模板：为常见场景（会议、项目、笔记）创建模板，标准化工作流程
- 使用Page Icon和Cover：为重要页面设置视觉标识，便于快速识别
- 充分利用双向链接：用@提及和[[链接]]建立页面间的知识关联
- 掌握块操作：熟练使用Cmd+D复制、Cmd+Shift+↑↓移动、Cmd+/选择块类型
- 定期整理工作区：每月审视一次页面结构，删除无用内容，合并相似页面
- 利用Database视图：对于重复性内容（如任务、项目），使用Database替代独立页面
- 备份重要数据：定期导出工作区内容，版本历史保留时间有限

