# Notion API Python SDK 基础用法
# 安装：pip install notion-client

from notion_client import Client
from datetime import datetime, timedelta

# 初始化 Notion 客户端（需要先在 Notion 获取 Integration Token）
notion = Client(auth="your_notion_integration_token")

# ============================================================
# 示例1：创建和管理数据库
# ============================================================

# 创建新数据库的父页面
parent_page_id = "your_parent_page_id"

# 定义数据库属性结构
new_database_properties = {
    "名称": {"title": {}},  # 标题属性（每个数据库必须）
    "状态": {
        "select": {
            "options": [
                {"name": "待办", "color": "gray"},
                {"name": "进行中", "color": "blue"},
                {"name": "已完成", "color": "green"}
            ]
        }
    },
    "优先级": {
        "select": {
            "options": [
                {"name": "高", "color": "red"},
                {"name": "中", "color": "yellow"},
                {"name": "低", "color": "default"}
            ]
        }
    },
    "负责人": {"people": {}},  # 人员属性
    "截止日期": {"date": {}},  # 日期属性
    "预算": {"number": {"format": "dollar"}},  # 数字属性（货币格式）
    "标签": {
        "multi_select": {
            "options": [
                {"name": "重要", "color": "red"},
                {"name": "紧急", "color": "orange"},
                {"name": "需要协作", "color": "blue"}
            ]
        }
    },
    "完成": {"checkbox": {}},  # 复选框属性
    "描述": {"rich_text": {}},  # 文本属性
    "相关链接": {"url": {}},  # 网址属性
}

# 创建数据库
new_database = notion.databases.create(
    parent={"type": "page_id", "page_id": parent_page_id},
    title=[{"type": "text", "text": {"content": "项目管理数据库"}}],
    properties=new_database_properties
)

print(f"新数据库创建成功，ID: {new_database['id']}")

# ============================================================
# 示例2：数据库的增删改查操作
# ============================================================

database_id = "your_database_id"

# 【CREATE】添加新记录
new_page = notion.pages.create(
    parent={"database_id": database_id},
    properties={
        "名称": {
            "title": [{"text": {"content": "市场调研项目"}}]
        },
        "状态": {"select": {"name": "待办"}},
        "优先级": {"select": {"name": "高"}},
        "截止日期": {
            "date": {
                "start": (datetime.now() + timedelta(days=30)).strftime("%Y-%m-%d")
            }
        },
        "预算": {"number": 50000},
        "标签": {"multi_select": [{"name": "重要"}, {"name": "需要协作"}]},
        "描述": {
            "rich_text": [{"text": {"content": "分析目标市场用户需求和竞争情况"}}]
        },
        "完成": {"checkbox": False}
    }
)

print(f"创建页面成功，ID: {new_page['id']}")
page_id = new_page['id']

# 【READ】查询数据库中的记录
# 查询所有记录
all_pages = notion.databases.query(database_id=database_id)
print(f"数据库中共有 {len(all_pages['results'])} 条记录")

# 【READ】带筛选条件查询
filtered_pages = notion.databases.query(
    database_id=database_id,
    filter={
        "property": "状态",
        "select": {"equals": "进行中"}
    }
)
print(f"进行中的项目: {len(filtered_pages['results'])} 个")

# 【READ】多条件筛选（AND）
