def batch_import_from_file(filepath):
    """
    从文本文件批量导入笔记
    文件格式：每条笔记用 --- 分隔
    """
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    # 按分隔符拆分笔记
    notes = content.split('---')

    success_count = 0
    for note in notes:
        if not note.strip():
            continue

        lines = note.strip().split('\n')
        if len(lines) < 2:
