// 1. npm install @notionhq/client
// 2. 设置环境变量 NOTION_TOKEN 和 NOTION_ROOT_PAGE_ID
// 3. node create-knowledge-base.js

// 知识库健康度检查脚本 - 检测过期文档并提醒负责人
// 此脚本检查知识库中的文档更新时间，识别需要审查的过期内容

const { Client } = require('@notionhq/client');

const notion = new Client({
  auth: process.env.NOTION_TOKEN
});

// 配置参数
const DATABASE_ID = process.env.NOTION_KB_DATABASE_ID;
const EXPIRY_THRESHOLD_DAYS = 30; // 超过30天未更新的文档视为过期

// 计算日期差异
function daysSinceUpdate(lastEditedTime) {
  const lastEdit = new Date(lastEditedTime);
  const now = new Date();
  const diffTime = Math.abs(now - lastEdit);
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
}

// 格式化日期为中文显示
function formatDate(dateString) {
  const date = new Date(dateString);
  return date.toLocaleDateString('zh-CN', {
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });
}

// 获取知识库中需要更新的文档
async function checkExpiredDocuments() {
  try {
    // 查询数据库中的所有页面
    const response = await notion.databases.query({
      database_id: DATABASE_ID,
      // 可以添加过滤条件，只检查特定状态的文档
      filter: {
        property: '状态',
        select: {
          does_not_equal: '已归档'
        }
      }
    });

    const expiredDocs = [];
    const healthyDocs = [];

    // 分析每篇文档
    for (const page of response.results) {
      const lastEdited = page.last_edited_time;
      const daysAgo = daysSinceUpdate(lastEdited);

      // 获取页面标题
      const title = page.properties?.名称?.title?.[0]?.plain_text || 
                    page.properties?.Title?.title?.[0]?.plain_text || 
                    '未命名页面';

      // 获取负责人信息（如果数据库中有此属性）
      const owner = page.properties?.负责人?.people?.[0]?.name || '未指定';

      const docInfo = {
        title,
        lastEdited: formatDate(lastEdited),
        daysAgo,
        owner,
        url: page.url
      };

      if (daysAgo > EXPIRY_THRESHOLD_DAYS) {
        expiredDocs.push(docInfo);
      } else {
        healthyDocs.push(docInfo);
      }
    }

    // 输出报告
    console.log('📊 知识库健康度检查报告\n');
    console.log(`检查时间: ${formatDate(new Date())}`);
    console.log(`文档总数: ${response.results.length}`);
    console.log(`健康文档: ${healthyDocs.length} 篇`);
    console.log(`过期文档: ${expiredDocs.length} 篇\n`);

    if (expiredDocs.length > 0) {
      console.log('⚠️  需要更新的文档：\n');
      console.log('| 文档名称 | 最后更新 | 距今天数 | 负责人 |');
      console.log('|----------|----------|----------|--------|');

      // 按过期天数排序
      expiredDocs.sort((a, b) => b.daysAgo - a.daysAgo);

      for (const doc of expiredDocs) {
        console.log(`| ${doc.title} | ${doc.lastEdited} | ${doc.daysAgo}天 | ${doc.owner} |`);
      }

      console.log('\n建议：\n1. 联系文档负责人确认内容是否仍然有效\n2. 更新文档或标注为「待审核」\n3. 如文档已过时，考虑归档或删除');
    }

    // 按负责人分组过期文档，便于发送提醒
    const ownerGroups = {};
    for (const doc of expiredDocs) {
      if (!ownerGroups[doc.owner]) {
        ownerGroups[doc.owner] = [];
      }
      ownerGroups[doc.owner].push(doc);
    }

    console.log('\n📧 按负责人分组的提醒列表：');
    for (const [owner, docs] of Object.entries(ownerGroups)) {
      console.log(`\n${owner} (${docs.length}篇待更新)：`);
      docs.forEach(d => console.log(`  - ${d.title} (${d.daysAgo}天未更新)`));
    }

    return {
      total: response.results.length,
      expired: expiredDocs,
      healthy: healthyDocs,
      byOwner: ownerGroups
    };

  } catch (error) {
    console.error('检查失败:', error.message);
    throw error;
  }
}

// 运行检查
checkExpiredDocuments()
  .then(report => {
    console.log('\n✅ 健康度检查完成');
  })
  .catch(err => {
    console.error('❌ 检查出错:', err);
  });

// 使用说明：
// 1. npm install @notionhq/client
// 2. 设置环境变量 NOTION_TOKEN 和 NOTION_KB_DATABASE_ID
// 3. 数据库需要包含「名称」「状态」「负责人」等属性
// 4. node health-check.js

