      '项目文档': 'Can Edit',
      '会议记录': 'Can Comment',
      '知识库': 'Can View',
    };

    const defaultAccess = defaultPermissions[category] || 'Can View';
    console.log(`   → 默认权限: ${defaultAccess}`);

    return { title, category, defaultAccess };
  }

  // 处理评论并提取任务
  async processCommentsForTasks(pageId) {
    const comments = await notion.comments.list({ block_id: pageId });

    const newTasks = [];

