// Example 2: Notion Database Query with AI-Enhanced Search
// This script demonstrates advanced querying and filtering for team knowledge

const { Client } = require('@notionhq/client');

const notion = new Client({
  auth: process.env.NOTION_API_KEY
});

/**
 * Query the knowledge base with multiple filters
 * Returns pages that match specified criteria
 */
async function queryKnowledgeBase(filters = {}) {
  const defaultFilters = {
    // Only show pages that need review (stale content detection)
    needsReview: false,
    // Filter by department
    department: null,
    // Minimum priority level
    minPriority: 'Low',
    // Only show published content
    status: 'Published'
  };

  const appliedFilters = { ...defaultFilters, ...filters };

  try {
    // Build filter conditions for the Notion API
    const filterConditions = [];

    // Status filter - only show published or ready for review
    if (appliedFilters.status) {
      filterConditions.push({
        property: 'Status',
        select: {
          equals: appliedFilters.status
        }
      });
    }

    // Department filter
    if (appliedFilters.department) {
      filterConditions.push({
        property: 'Department',
        select: {
          equals: appliedFilters.department
        }
      });
    }

    // Date filter - find pages past their review date
    if (appliedFilters.needsReview) {
      filterConditions.push({
        property: 'Review Date',
        date: {
          before: new Date().toISOString()
        }
      });
    }

    // Priority filter
    const priorityOrder = ['Low', 'Medium', 'High', 'Critical'];
    const minPriorityIndex = priorityOrder.indexOf(appliedFilters.minPriority);
    if (minPriorityIndex !== -1) {
      filterConditions.push({
        or: priorityOrder
          .slice(minPriorityIndex)
          .map(p => ({
            property: 'Priority',
            select: { equals: p }
          }))
      });
    }

    // Execute query with filters
    const response = await notion.databases.query({
      database_id: 'your-knowledge-base-id',
      filter: filterConditions.length > 1 
        ? { and: filterConditions } 
        : filterConditions[0],
      sorts: [
        {
          property: 'Last Updated',
          direction: 'descending'
        },
        {
          property: 'Priority',
          direction: 'ascending'
        }
      ],
      page_size: 50
    });

    console.log(`📚 Found ${response.results.length} pages matching criteria`);
    return response.results;

  } catch (error) {
    console.error('❌ Query failed:', error.message);
    throw error;
  }
}

/**
 * Get page content and extract AI-generated summary
 */
async function getPageSummary(pageId) {
  try {
    // Retrieve page properties
    const page = await notion.pages.retrieve({ page_id: pageId });

    // Retrieve page blocks (content)
    const blocks = await notion.blocks.children.list({ block_id: pageId });

    // Extract text content from blocks
    const textContent = blocks.results
      .filter(block => block.type === 'paragraph')
      .map(block => block.paragraph.rich_text.map(t => t.plain_text).join(''))
      .join('\n');

    // Return structured summary data
    return {
      id: page.id,
      title: page.properties.Name?.title[0]?.plain_text || 'Untitled',
      department: page.properties.Department?.select?.name || 'Uncategorized',
      status: page.properties.Status?.select?.name || 'Unknown',
      owner: page.properties.Owner?.people?.[0]?.name || 'Unassigned',
      reviewDate: page.properties['Review Date']?.date?.start || null,
      contentLength: textContent.length,
      lastEdited: page.last_edited_time,
      url: `https://notion.so/${pageId.replace(/-/g, '')}`
    };

  } catch (error) {
    console.error('❌ Error getting page summary:', error.message);
    throw error;
  }
}

/**
 * Generate a team knowledge dashboard report
 */
async function generateKnowledgeReport() {
  console.log('📊 Generating Knowledge Base Report...\n');

  // Get all content by status
  const allContent = await queryKnowledgeBase({ status: null });

  // Get content needing review
  const needsReview = await queryKnowledgeBase({ needsReview: true });

  // Get content by department
  const departments = ['Engineering', 'Marketing', 'Sales', 'HR', 'Operations'];
  const byDepartment = {};

  for (const dept of departments) {
    const pages = await queryKnowledgeBase({ department: dept });
    byDepartment[dept] = pages.length;
  }

  // Generate report
  const report = {
    generatedAt: new Date().toISOString(),
    summary: {
      totalPages: allContent.length,
      needsReview: needsReview.length,
      healthPercentage: Math.round(
        ((allContent.length - needsReview.length) / allContent.length) * 100
      )
    },
    byDepartment,
    topPriorityItems: (await queryKnowledgeBase({ minPriority: 'High' })).slice(0, 5)
  };

  console.log('📈 Knowledge Base Health:', report.summary.healthPercentage + '%');
  console.log('📄 Total Pages:', report.summary.totalPages);
  console.log('⚠️ Pages Needing Review:', report.summary.needsReview);
  console.log('\n📊 By Department:');
  Object.entries(report.byDepartment).forEach(([dept, count]) => {
    console.log(`  ${dept}: ${count} pages`);
  });

  return report;
}

// Export functions for use in other modules
module.exports = {
  queryKnowledgeBase,
  getPageSummary,
  generateKnowledgeReport
};

// Uncomment to run directly:
