            rich_text: [{
              text: { content: pageData.overview || 'Add overview here...' },
              annotations: { italic: true }
            }]
          }
        },
        // Key Information section
        {
          object: 'heading_1',
          type: 'heading_1',
          heading_1: { rich_text: [{ text: { content: 'Key Information' } }] }
        },
