    return response;
  } catch (error) {
    console.error('❌ Error creating wiki page:', error.message);
    throw error;
  }
}

// Helper function to set default review date (30 days from now)
function getDefaultReviewDate() {
  const date = new Date();
  date.setDate(date.getDate() + 30);
  return date.toISOString().split('T')[0];
}

// Example usage: Create multiple wiki pages for a new team
async function setupTeamWiki() {
  const teamPages = [
    {
      title: 'Engineering Team Handbook',
      department: 'Engineering',
      ownerId: 'notion-user-id-1',
      priority: 'High',
      overview: 'Complete guide to engineering team processes, standards, and practices.'
    },
    {
      title: 'Marketing Playbook',
      department: 'Marketing',
      ownerId: 'notion-user-id-2',
      priority: 'High',
