#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Notion API 批量导入笔记示例
功能：从文本文件批量创建 Notion 页面
"""

import requests
import json
from datetime import datetime

# ==================== 配置区域 ====================
NOTION_API_KEY = "your_integration_token_here"
DATABASE_ID = "your_database_id_here"

# Notion API 端点
NOTION_API_URL = "https://api.notion.com/v1/pages"
HEADERS = {
    "Authorization": f"Bearer {NOTION_API_KEY}",
    "Content-Type": "application/json",
    "Notion-Version": "2022-06-28"
}

def create_notion_page(title, content, tags, source_url):
    """
    创建单个 Notion 页面

    参数:
        title (str): 页面标题
        content (str): 页面正文内容
        tags (list): 标签列表
        source_url (str): 原始链接

    返回:
        dict: API 响应结果
    """
    payload = {
        "parent": {"database_id": DATABASE_ID},
        "properties": {
            "标题": {
                "title": [
                    {"text": {"content": title}}
                ]
            },
            "标签": {
                "multi_select": [
                    {"name": tag} for tag in tags
                ]
            },
            "来源": {
                "url": source_url
            },
            "采集时间": {
                "date": {
                    "start": datetime.now().isoformat()
                }
            },
            "状态": {
                "select": {"name": "待处理"}
            }
        },
        "children": [
            {
                "object": "block",
                "type": "heading_2",
                "heading_2": {
                    "rich_text": [{"type": "text", "text": {"content": "内容摘要"}}]
                }
            },
            {
                "object": "block",
                "type": "paragraph",
                "paragraph": {
                    "rich_text": [{"type": "text", "text": {"content": content}}]
                }
            }
        ]
    }

    response = requests.post(NOTION_API_URL, headers=HEADERS, json=payload)
    return response.json()

def batch_import_from_file(filepath):
    """
    从文本文件批量导入笔记
    文件格式：每条笔记用 --- 分隔
    """
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    # 按分隔符拆分笔记
    notes = content.split('---')

    success_count = 0
    for note in notes:
        if not note.strip():
            continue

        lines = note.strip().split('\n')
        if len(lines) < 2:
            continue

        # 简单解析：第一行是标题，第二行是内容
        title = lines[0].replace('标题：', '').strip()
        body = '\n'.join(lines[1:])

        try:
            result = create_notion_page(
                title=title,
                content=body,
                tags=["API导入", "批量处理"],
                source_url=""
            )
            if result.get('id'):
                success_count += 1
                print(f"✓ 成功创建：{title}")
        except Exception as e:
            print(f"✗ 创建失败：{title}, 错误：{e}")

    print(f"\n导入完成：成功 {success_count}/{len(notes)} 条")

if __name__ == "__main__":
    # 示例：创建单条笔记
    result = create_notion_page(
        title="测试笔记：通过API导入",
        content="这是一条通过 Python API 创建的测试笔记，用于验证 Notion 集成是否正常工作。",
        tags=["测试", "API"],
        source_url="https://example.com/article"
    )
    print("创建结果：", json.dumps(result, ensure_ascii=False, indent=2))
