#!/usr/bin/env node
/**
 * Notion Web Clipper 自动化脚本
 * 功能：监控网页内容，自动提取并创建 Notion 页面
 * 使用场景：需要批量处理收集的文章时
 */

const { Client } = require("@notionhq/client");

// 初始化 Notion 客户端
const notion = new Client({
  auth: process.env.NOTION_API_KEY,
});

// 配置常量
const INBOX_DATABASE_ID = "your_inbox_database_id";

/**
 * 从文章页面提取关键信息
 * @param {string} url - 文章 URL
 * @returns {Object} 提取的内容对象
 */
async function extractArticleContent(url) {
  // 注意：实际使用时需要配合 cheerio 或 puppeteer 抓取页面
  // 这里使用模拟数据演示

  return {
    title: "文章标题",
    url: url,
    author: "作者名",
    publishDate: new Date().toISOString(),
    summary: "文章核心观点摘要...",
    keyPoints: [
      "要点1：xxx",
      "要点2：xxx",
      "要点3：xxx"
    ],
    tags: ["待分类", "待阅读"]
  };
}

/**
 * 在 Notion Inbox 中创建新页面
 * @param {Object} article - 文章内容对象
 * @returns {string} 创建的页面 ID
 */
async function createInboxPage(article) {
  try {
    const response = await notion.pages.create({
      parent: { database_id: INBOX_DATABASE_ID },
      properties: {
        // 标题属性（根据你的数据库字段名调整）
        "名称": {
          title: [
            {
              text: {
                content: article.title,
              },
            },
          ],
        },
        // 标签属性
        "标签": {
          multi_select: article.tags,
        },
        // 来源 URL
        "来源": {
          url: article.url,
        },
        // 采集时间
        "采集时间": {
          date: {
            start: article.publishDate,
          },
        },
        // 状态：默认待处理
        "状态": {
          select: {
            name: "待阅读",
          },
        },
      },
      // 页面内容块
      children: [
        {
          object: "block",
          type: "heading_2",
          heading_2: {
            rich_text: [
              {
                type: "text",
                text: { content: "📌 核心摘要" },
              },
            ],
          },
        },
        {
          object: "block",
          type: "paragraph",
          paragraph: {
            rich_text: [
              {
                type: "text",
                text: { content: article.summary },
              },
            ],
          },
        },
        {
          object: "block",
          type: "heading_2",
          heading_2: {
            rich_text: [
              {
                type: "text",
                text: { content: "💡 关键要点" },
              },
            ],
          },
        },
        ...article.keyPoints.map((point, index) => ({
          object: "block",
          type: "bulleted_list_item",
          bulleted_list_item: {
            rich_text: [
              {
                type: "text",
                text: { content: point },
              },
            ],
          },
        })),
      ],
    });

    console.log(`✅ 页面创建成功: ${response.id}`);
    return response.id;
  } catch (error) {
    console.error("❌ 创建页面失败:", error);
    throw error;
  }
}

/**
 * 主函数：批量处理 URL 列表
 * @param {string[]} urls - URL 数组
 */
async function processBatchURLs(urls) {
  console.log(`🚀 开始处理 ${urls.length} 个 URL...\n`);

  const results = {
    success: 0,
    failed: 0,
    errors: []
  };

  for (const url of urls) {
    try {
      // 1. 提取内容
      console.log(`📥 正在处理: ${url}`);
      const article = await extractArticleContent(url);

      // 2. 创建页面
      await createInboxPage(article);

      results.success++;

      // 礼貌性延迟，避免 API 限流
      await new Promise(resolve => setTimeout(resolve, 1000));

    } catch (error) {
      results.failed++;
      results.errors.push({ url, error: error.message });
    }
  }

  // 输出统计
  console.log("\n" + "=".repeat(50));
  console.log("📊 处理完成");
  console.log(`✓ 成功: ${results.success}`);
  console.log(`✗ 失败: ${results.failed}`);

  if (results.errors.length > 0) {
    console.log("\n错误详情:");
    results.errors.forEach(e => console.log(`  - ${e.url}: ${e.error}`));
  }
}

// 运行示例
const testURLs = [
  "https://example.com/article1",
  "https://example.com/article2",
  "https://example.com/article3",
];

processBatchURLs(testURLs);

// 导出供其他模块使用
module.exports = { createInboxPage, extractArticleContent };

