}

// 示例2: 搜索特定权限级别的页面
async function findPagesByPermissionLevel() {
  // 搜索标记为特定权限组的所有页面
  const response = await notion.search({
    filter: {
      value: 'page',
      property: 'object',
    },
    sort: {
      direction: 'descending',
      timestamp: 'last_edited_time',
    },
  });

  // 过滤特定权限组的页面
  const restrictedPages = response.results.filter(page => {
    const permissionProperty = page.properties['权限级别'];
    return permissionProperty?.select?.name === '机密';
  });

  console.log(`找到 ${restrictedPages.length} 个受限页面`);
  return restrictedPages;
}

// 示例3: 更新页面状态（模拟权限变更流程）
async function updatePageStatus(pageId, newStatus) {
  try {
    await notion.pages.update({
      page_id: pageId,
      properties: {
        '状态': {
          select: { name: newStatus },
        },
        '最后更新': {
          date: { start: new Date().toISOString() },
        },
      },
    });
    console.log('页面状态已更新');
  } catch (error) {
    console.error('更新失败:', error.message);
  }
}

// 示例4: 获取页面评论（团队协作记录）
async function getPageComments(pageId) {
  const response = await notion.comments.list({
    block_id: pageId,
  });

  console.log('页面评论列表:');
  response.results.forEach(comment => {
    const author = comment.created_by?.name || '未知';
    const time = new Date(comment.created_time).toLocaleString('zh-CN');
    const content = comment.rich_text?.map(t => t.plain_text).join('') || '';

    console.log(`[${time}] ${author}: ${content}`);
  });

  return response.results;
}

// 示例5: 创建待办任务（任务分配）
async function createTask(databaseId, taskDetails) {
  const response = await notion.pages.create({
    parent: { database_id: databaseId },
    properties: {
      '任务名称': {
        title: [{ text: { content: taskDetails.title } }],
      },
      '负责人': {
        people: [{ id: taskDetails.assigneeId }],
      },
      '截止日期': {
        date: { start: taskDetails.dueDate },
      },
      '优先级': {
        select: { name: taskDetails.priority || '中' },
      },
      '状态': {
        select: { name: '待处理' },
      },
    },
  });

  console.log(`任务创建成功: ${taskDetails.title}`);
  return response;
}

// 导出所有函数供外部使用
module.exports = {
  createProjectPage,
  findPagesByPermissionLevel,
  updatePageStatus,
  getPageComments,
  createTask,
};
```

### 示例 2

```python
// Notion协作流程自动化示例
// 结合Notion API和外部工具实现自动化协作流程

const { Client } = require('@notionhq/client');

const notion = new Client({ auth: process.env.NOTION_TOKEN });

// 示例: 项目文档协作流程自动化

// 1. 监听页面变化并自动通知相关成员
class CollaborationWorkflow {
  constructor() {
    this.pendingTasks = [];
  }

  // 处理新页面创建
  async handleNewPageCreated(page) {
    const title = page.properties?.title?.title?.[0]?.plain_text || '未命名';
    const category = page.properties?.类别?.select?.name || '未分类';

    console.log(`📄 新页面创建: ${title}`);

    // 根据页面类型设置默认权限
    const defaultPermissions = {
      '项目文档': 'Can Edit',
      '会议记录': 'Can Comment',
      '知识库': 'Can View',
    };

    const defaultAccess = defaultPermissions[category] || 'Can View';
    console.log(`   → 默认权限: ${defaultAccess}`);

    return { title, category, defaultAccess };
  }

  // 处理评论并提取任务
  async processCommentsForTasks(pageId) {
    const comments = await notion.comments.list({ block_id: pageId });

    const newTasks = [];

    for (const comment of comments.results) {
      const content = comment.rich_text
        ?.map(t => t.plain_text)
        ?.join('') || '';

      // 检测@任务格式: @任务: 具体内容
      const taskMatch = content.match(/@任务:\s*(.+)/i);
      if (taskMatch) {
        const taskDescription = taskMatch[1];
        const mentionedPeople = comment.mentions?.user || [];

        newTasks.push({
          description: taskDescription,
          assignees: mentionedPeople.map(p => p.id),
          createdAt: comment.created_time,
          createdBy: comment.created_by?.id,
        });

        console.log(`✅ 检测到任务: ${taskDescription}`);
        if (mentionedPeople.length > 0) {
          console.log(`   → 负责人: ${mentionedPeople.map(p => p.name).join(', ')}`);
        }
      }
    }

    return newTasks;
  }

  // 自动更新权限变更历史
  async logPermissionChange(pageId, oldPermission, newPermission, changedBy) {
    const logPage = await this.findOrCreateLogPage();

    await notion.blocks.children.append({
      block_id: logPage.id,
      children: [
        {
          object: 'block',
          type: 'bulleted_list_item',
          bulleted_list_item: {
            rich_text: [
              {
                type: 'text',
                text: {
                  content: `权限变更: ${oldPermission} → ${newPermission}`,
                },
              },
            ],
            annotations: {
              bold: true,
            },
          },
        },
        {
          object: 'block',
          type: 'bulleted_list_item',
          bulleted_list_item: {
            rich_text: [
              {
                type: 'text',
                text: {
                  content: `变更人: ${changedBy}`,
                },
              },
            ],
          },
        },
        {
          object: 'block',
          type: 'bulleted_list_item',
          bulleted_list_item: {
            rich_text: [
              {
                type: 'text',
                text: {
                  content: `时间: ${new Date().toLocaleString('zh-CN')}`,
                },
              },
            ],
          },
        },
      ],
    });

    console.log('📝 权限变更已记录');
  }

  // 生成团队协作报告
  async generateCollaborationReport(databaseId) {
    const database = await notion.databases.query({
      database_id: databaseId,
    });

    const report = {
      totalPages: database.results.length,
      byCategory: {},
      recentlyUpdated: [],
      highPriority: [],
    };

    for (const page of database.results) {
      // 按类别统计
      const category = page.properties?.类别?.select?.name || '未分类';
      report.byCategory[category] = (report.byCategory[category] || 0) + 1;

      // 最近更新的页面（最近7天）
      const lastEdited = new Date(page.last_edited_time);
      const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
      if (lastEdited > sevenDaysAgo) {
        report.recentlyUpdated.push({
          title: page.properties?.title?.title?.[0]?.plain_text || '未命名',
          lastEdited: lastEdited.toLocaleDateString('zh-CN'),
        });
      }
    }

    console.log('=== 团队协作报告 ===');
    console.log(`总页面数: ${report.totalPages}`);
    console.log('按类别统计:', report.byCategory);
    console.log(`最近7天更新: ${report.recentlyUpdated.length} 个页面`);

    return report;
  }
}

// 使用示例
async function main() {
  const workflow = new CollaborationWorkflow();

  // 模拟处理新页面
  await workflow.handleNewPageCreated({
    properties: {
      title: { title: [{ plain_text: 'Q4产品规划' }] },
      '类别': { select: { name: '项目文档' } },
    },
  });

  // 生成报告
  await workflow.generateCollaborationReport('your-database-id');
}

module.exports = CollaborationWorkflow;
```



## 常见错误

- 将所有页面设置为Can Edit，导致权限失控和安全风险
- 忘记子页面会继承父页面权限，意外泄露敏感信息
- 使用访客(Guest)账号访问内部机密页面，缺乏隔离机制
- 未定期清理离职成员权限，造成权限残留风险
- 在公共工作区分享含有敏感信息的页面，忽视访问控制
- 误认为删除页面即可清除所有权限历史，忽视审计需求
- 为图方便给整个团队Full Access，违反最小权限原则
- 在Notion API中暴露token或权限配置信息到客户端代码
- 未建立权限变更审批流程，导致权限配置混乱
- 忽略数据库视图级别的权限设置，仅设置页面权限


## 最佳实践

- 遵循最小权限原则：仅授予完成工作所需的最低权限级别
- 建立清晰的权限层级结构：工作区→空间→页面→数据库
- 使用命名规范标识敏感页面：如添加[机密]、[内部]前缀
- 定期进行权限审计：建议每月检查一次成员和权限配置
- 为不同角色创建权限模板：简化常见权限配置场景
- 善用页面级权限覆盖：子页面需要不同权限时单独设置
- 分离内部协作和外部协作：使用不同工作区或严格限制访客权限
- 记录权限变更日志：建立变更追溯机制，便于审计和问题排查
- 结合评论@提及功能：减少不必要的Full Access授予
- 使用企业版的行级权限：对数据库实现更细粒度的访问控制

