            "text": "📚 知识库更新提醒",
            "blocks": blocks
        }

        response = requests.post(
            SLACK_WEBHOOK_URL,
            headers={"Content-Type": "application/json"},
            data=json.dumps(payload)
        )

        if response.status_code == 200:
            print(f"✅ 已发送提醒通知")
        else:
            print(f"❌ 发送失败: {response.text}")

def main():
